const FALLBACK_CATEGORY_COLOR: Record<ElementCategoryToken, string> = {
  wall: '#ddd8d0',
  floor: '#cfc9be',
  roof: 'hsl(0 18% 40%)',
  door: '#b8a898',
  window: 'hsl(213 60% 70%)',
