function withDefaultMetadata(spec: MaterialPbrSpec): MaterialPbrSpec {
  return {
    ...spec,
    source: spec.source ?? 'builtin',
    reflectance: spec.reflectance ?? Math.max(0, Math.min(1, 1 - spec.roughness)),
